import{_ as e,o as t,c as r,a3 as i}from"./chunks/framework.ZM1D-rQ5.js";const u=JSON.parse('{"title":"Builder Library","description":"","frontmatter":{},"headers":[],"relativePath":"builder/library.md","filePath":"builder/library.md","lastUpdated":1781186938000}'),o={name:"builder/library.md"};function n(l,a,s,d,b,h){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="builder-library" tabindex="-1">Builder Library <a class="header-anchor" href="#builder-library" aria-label="Permalink to &quot;Builder Library&quot;">​</a></h1><p>The Library lets you save containers and columns as reusable templates. Unlike Global Sections, library items are <strong>independent copies</strong> — editing one insert doesn&#39;t affect others.</p><h2 id="saving-to-library" tabindex="-1">Saving to Library <a class="header-anchor" href="#saving-to-library" aria-label="Permalink to &quot;Saving to Library&quot;">​</a></h2><h3 id="save-a-container" tabindex="-1">Save a Container <a class="header-anchor" href="#save-a-container" aria-label="Permalink to &quot;Save a Container&quot;">​</a></h3><ol><li>Hover over a container</li><li>Click the <strong>📚 Library</strong> icon on the container toolbar</li><li>Give it a name (e.g., &quot;Hero Banner Blue&quot;)</li><li>Click <strong>Save</strong></li></ol><h3 id="save-a-column" tabindex="-1">Save a Column <a class="header-anchor" href="#save-a-column" aria-label="Permalink to &quot;Save a Column&quot;">​</a></h3><ol><li>Hover over a column</li><li>Click the <strong>📚 Library</strong> icon on the column toolbar</li><li>Give it a name (e.g., &quot;Feature Card&quot;)</li><li>Click <strong>Save</strong></li></ol><h2 id="using-library-items" tabindex="-1">Using Library Items <a class="header-anchor" href="#using-library-items" aria-label="Permalink to &quot;Using Library Items&quot;">​</a></h2><ol><li>Click <strong>+ Add Container</strong> to open the Column Select modal</li><li>Click the <strong>Container Library</strong> tab (or <strong>Column Library</strong> when adding columns)</li><li>Find your saved item</li><li>Click <strong>Add Container</strong> / <strong>Add Column</strong></li></ol><p>The item is inserted as an independent copy — you can edit it freely without affecting other pages.</p><h2 id="managing-the-library" tabindex="-1">Managing the Library <a class="header-anchor" href="#managing-the-library" aria-label="Permalink to &quot;Managing the Library&quot;">​</a></h2><p>From the Column Select modal:</p><ul><li><strong>Delete</strong> any saved item with the 🗑️ button</li><li>Library items are shared across all pages</li></ul><h2 id="library-vs-global-sections" tabindex="-1">Library vs Global Sections <a class="header-anchor" href="#library-vs-global-sections" aria-label="Permalink to &quot;Library vs Global Sections&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Library</th><th>Global Section</th></tr></thead><tbody><tr><td>Edit propagates everywhere</td><td>❌ No</td><td>✅ Yes</td></tr><tr><td>Edit per-page</td><td>✅ Yes</td><td>❌ No</td></tr><tr><td>Best for</td><td>Reusing a design as a starting point</td><td>Consistent content across pages (header CTA, promo banner)</td></tr></tbody></table>',15)])])}const g=e(o,[["render",n]]);export{u as __pageData,g as default};
